import{c as i,Q as a,j as o,m as t}from"./chunks/framework.rlpw0eGz.js";const r="/assets/image_025.BU0pU6nm.png",s="/assets/image_011.CDtB_yEf.png",l="/assets/image_001.D0m7-JiF.png",n="/assets/image_035.CJ3uhTNn.png",p="/assets/image_027.DILbfCT9.png",c="/assets/image_018.CRfXic3K.png",m="/assets/image_005.CBoOGyO_.png",d="/assets/image_020.mEZoEI2N.png",g="/assets/image_028.C1RlR4Qw.png",u="/assets/image_021.B9TTjomp.png",x="/assets/image_010.BB3N_odC.png",_="/assets/image_039.BcgWMCli.png",h="/assets/image_013.f7oWYrQR.png",D="/assets/image_029.CT-BLnUh.png",b="/assets/image_006.D8lCU-PY.png",f="/assets/image_004.B5vKlBqp.png",v="/assets/image_033.B74ItOSF.png",z="/assets/image_007.B6EdCS8f.png",S="/assets/image_016.CktkUuia.png",O="/assets/image_041.C_4XYWlq.png",I=JSON.parse('{"title":"Condividere le letture di Dex con xDrip4iOS","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/Condividere-le-letture-di-Dexcom-con-xDrip4iOS/condividere-le-letture-di-dexcom-one-g6-con-xdrip4ios-shuggah.md","filePath":"documentation/Condividere-le-letture-di-Dexcom-con-xDrip4iOS/condividere-le-letture-di-dexcom-one-g6-con-xdrip4ios-shuggah.md","lastUpdated":1780253090000}'),w={name:"documentation/Condividere-le-letture-di-Dexcom-con-xDrip4iOS/condividere-le-letture-di-dexcom-one-g6-con-xdrip4ios-shuggah.md"};function C(q,e,B,G,k,P){return a(),o("div",null,[...e[0]||(e[0]=[t('<p>Una soluzione fai da te per condividere la glicemia con altri telefoni e visualizzare la glicemia su Apple Watch con il calendario o una complicazione.</p><h1 id="condividere-le-letture-di-dex-con-xdrip4ios" tabindex="-1">Condividere le letture di Dex con <a href="https://www.facebook.com/groups/853994615056838/" target="_blank" rel="noreferrer">xDrip4iOS</a> <a class="header-anchor" href="#condividere-le-letture-di-dex-con-xdrip4ios" aria-label="Permalink to &quot;Condividere le letture di Dex con [xDrip4iOS](https://www.facebook.com/groups/853994615056838/)&quot;">​</a></h1><p>Dex One, per la mancanza del sistema di condivisione Dex Share a cui siamo abituati dai suoi predecessori Dex G5/6, ha bisogno di una soluzione fai da te per condividere la glicemia con altri telefoni e visualizzare la glicemia su Apple Watch con il calendario o una complicazione.</p><p>Questa guida passo passo spiega come impostare l’app xDrip4iOS, per poter condividere la glicemia.</p><p>Il sensore deve essere stato avviato con l’app Dexcom. Assicurarsi che funzioni correttamente prima di andare avanti.</p><ul><li><a href="#installare-xdrip4ios">Installare xDrip4iOS</a></li><li><a href="#disabilitare-lapp-dexcom-solo-per-dexcom-g6-dexcom-one">Disabilitare l&#39;app Dex solo per Dex G6 / Dex One</a></li><li><a href="#abbinare-il-trasmettitore">Abbinare il trasmettitore con xDrip4iOS</a></li><li><a href="#opzione-segui-lapp-dexcom-read-from-dexcom-app">Opzione &quot;Segui l&#39;app Dexcom&quot; / Read from Dex app</a></li></ul><h1 id="installare-xdrip4ios" tabindex="-1">Installare xDrip4iOS <a class="header-anchor" href="#installare-xdrip4ios" aria-label="Permalink to &quot;Installare xDrip4iOS&quot;">​</a></h1><p><a id="disabilitare-lapp-dexcom-solo-per-dexcom-g6-dexcom-one"></a></p><h1 id="disabilitare-l-app-dex-solo-per-dex-g6-dex-one" tabindex="-1">Disabilitare l&#39;app Dex solo per Dex G6 / Dex One <a class="header-anchor" href="#disabilitare-l-app-dex-solo-per-dex-g6-dex-one" aria-label="Permalink to &quot;Disabilitare l&#39;app Dex solo per Dex G6 / Dex One&quot;">​</a></h1><p style="font-size:1.6em;font-weight:600;">Per Dex G7 / Dex One + (plus) vedi in seguito</p><p>Per evitare problemi con l&#39;app master Dex G6/ONE che &quot;ruba&quot; la connessione Bluetooth da xDrip4iOS, dobbiamo assicurarci che abbia le autorizzazioni Bluetooth disabilitate.</p><p>Vai alle Impostazioni del tuo iPhone e scorri verso il basso e cerca l’elenco delle applicazioni. Seleziona l&#39;app Dex e, nelle opzioni, disattiva il Bluetooth. Potrai riattivarlo in seguito, se lo desideri.</p><p><img src="'+r+'" alt="image_025"></p><p><a id="abbinare-il-trasmettitore"></a></p><h1 id="abbinare-il-trasmettitore-con-xdrip4ios" tabindex="-1">Abbinare il trasmettitore con xDrip4iOS <a class="header-anchor" href="#abbinare-il-trasmettitore-con-xdrip4ios" aria-label="Permalink to &quot;Abbinare il trasmettitore con xDrip4iOS&quot;">​</a></h1><p>Accedere alla scheda Bluetooth dell’app xDrip4iOS e fare clic sul pulsante + per aggiungere un nuovo tipo di dispositivo.</p><p><img src="'+s+'" alt="image_011"></p><p>Seleziona CGM e poi scegli il tuo sistema Dex (G5/G6/One) dall&#39;elenco.</p><p><img src="'+l+'" alt="image_001"></p><p>Ti verrà richiesto di inserire l&#39;ID del trasmettitore (ad esempio: 80H9W4), inserisci il tuo.</p><p><img src="'+n+'" alt="image_035"></p><p>Una volta inserito l&#39;ID del trasmettitore, verrà visualizzato un messaggio che ti chiede di mantenere aperto xDrip4iOS mentre viene trovato il trasmettitore e viene stabilita una connessione Bluetooth. Lascia il tuo iPhone sul tavolo e prendi un caffè. NON giocare a Roblox, guardare Netflix o ascoltare Spotify. Metti giù il telefono senza toccarlo e restagli vicino.</p><p><img src="'+p+'" alt="image_027"></p><p><img src="'+c+'" alt="image_018"></p><p>Quando xDrip4iOS trova il tuo trasmettitore, riceverai un messaggio che dice che è stato collegato correttamente. Fare clic su OK.</p><p>Una volta connesso, vedrai sempre il suo stato come Scansione poiché comunica solo per un breve periodo di tempo ogni 5 minuti.</p><p><img src="'+m+'" alt="image_005"><img src="'+d+'" alt="image_020"></p><p>Se utilizzi un sensore Dex G6 o ONE, ti verrà richiesto di inserire il codice di calibrazione riportato sulla scatola del sensore una volta completato il riscaldamento.</p><p><a id="opzione-segui-lapp-dexcom-read-from-dexcom-app"></a></p><h1 id="opzione-segui-l-app-dexcom-read-from-dex-app" tabindex="-1">Opzione &quot;Segui l&#39;app Dexcom&quot; / Read from Dex app <a class="header-anchor" href="#opzione-segui-l-app-dexcom-read-from-dex-app" aria-label="Permalink to &quot;Opzione &quot;Segui l&#39;app Dexcom&quot; / Read from Dex app&quot;">​</a></h1><p>Una volta accoppiato il trasmettitore, puoi abilitare Follow Dex app/ Read from Dex app e riattivare il Bluetooth nell&#39;app Dex sul tuo telefono. Sia xDrip4iOS che l&#39;app Dex saranno collegati al sensore. Ciò ti consente di utilizzare il meglio di entrambi i mondi (caricamenti Clarity e funzionalità uniche di xDrip4iOS). In questo caso, xDrip4iOS spierà semplicemente le comunicazioni tra il trasmettitore e l&#39;app Dexcom.</p><p><img src="'+g+'" alt="image_028"></p><p>Nota: se non hai l&#39;app Dex ufficiale installata sul tuo iPhone e collegata al trasmettitore, non abilitare questa opzione altrimenti non riceverai alcuna lettura.</p><p>È possibile che i valori non siano subito presenti nella schermata principale ma solo il grafico e in basso viene riconosciuto il sensore e presente anche TIR.</p><p>Funziona, recupererà anche il numero.</p><p><img src="'+u+'" alt="image_021"></p><p>Se non hai ancora sul telefono la schermata precedente o i valori, dopo aver seguito tutti i passaggi correttamente, puoi disinstallare l’app Dex senza fermare il sensore e riprendere la procedura per xDrip4iOS. Appena xDrip4iOS sarà funzionale puoi reinstallare l’app Dex e abilitare Follow Dex app/ Read from Dex app in xDrip4iOS.</p><p>Dex G6 ha il suo sistema di condivisione tramite Dex share server che manda i dati dall&#39;app Dex G6 (collegata al sensore) all&#39;app Dex Follow usata dai genitori/caregiver per seguire a distanza.</p><p>Questo è un sistema molto valido rispetto ad altri sensori finché funziona; i problemi sorgono quando, raramente è vero, il sistema è fermo per vari motivi (manutenzione programmata, guasti, ecc.).</p><p>In questo modo hai sempre attivi due sistemi di condivisione, con la condizione che l&#39;app Dex funzioni.</p><p>Se l&#39;app Dex non funziona, ricordiamo che xDrip4iOS può essere collegato direttamente al sensore; è consigliato solo in casi particolari, altrimenti l&#39;app Dex ufficiale è la soluzione più semplice e stabile.</p><h1 id="abbinare-il-trasmettitore-per-dex-g7-one" tabindex="-1">Abbinare il trasmettitore per Dex G7 / ONE+ <a class="header-anchor" href="#abbinare-il-trasmettitore-per-dex-g7-one" aria-label="Permalink to &quot;Abbinare il trasmettitore per Dex G7 / ONE+&quot;">​</a></h1><p><img src="'+x+'" alt="image_010"></p><p>Accedere alla scheda Bluetooth dell’app xDrip4iOS e fare clic sul pulsante + per aggiungere un nuovo tipo di dispositivo.</p><p>Seleziona CGM e poi scegli G7 / ONE+ / Stelo. <img src="'+_+'" alt="image_039"><img src="'+h+'" alt="image_013"><img src="'+D+'" alt="image_029"><img src="'+b+'" alt="image_006"></p><p>Scegliere ‘Scanning’ e selezionare OK al messaggio successivo. <img src="'+f+'" alt="image_004"></p><p>Se possibile, non uscire dalla schermata. Aspetta…</p><p>Una volta collegato, darà una schermata così.</p><p>Il codice del sensore è presente nei dispositivi BT</p><p><img src="'+v+'" alt="image_033"><img src="'+z+'" alt="image_007"></p><p>Torna alla schermata principale dell’app.</p><p>Dovrebbe essere presente la glicemia e un solo valore sul grafico.</p><p><img src="'+S+'" alt="image_016"></p><p>Per condividere la glicemia con altri telefoni e utilizzare smartwatch diversi da Apple Watch (Fitbit, Garmin, Samsung Gear) serve Nightscout <a href="https://www.glicemiadistanza.it/nightscout/" target="_blank" rel="noreferrer">https://www.glicemiadistanza.it/nightscout/</a> o Gluroo <a href="https://www.glicemiadistanza.it/gluroo/" target="_blank" rel="noreferrer">https://www.glicemiadistanza.it/gluroo/</a></p><p>La documentazione originale (link con traduttore automatico): <a href="https://xdrip4ios-readthedocs-io.translate.goog/en/latest/connect/cgm/?_x_tr_sl=auto&amp;_x_tr_tl=it" target="_blank" rel="noreferrer">https://xdrip4ios-readthedocs-io.translate.goog/en/latest/connect/cgm/?_x_tr_sl=auto&amp;_x_tr_tl=it</a></p><p><img src="'+O+'" alt="image_041"></p><p><strong>L&#39;utilizzo è soggetto all&#39;assunzione di esclusiva responsabilità personale.</strong></p><p>Contatti <a href="https://www.facebook.com/groups/nightscout" target="_blank" rel="noreferrer">Diabete, glicemia a distanza e nuove tecnologie</a></p>',58)])])}const N=i(w,[["render",C]]);export{I as __pageData,N as default};
